<template>
    <el-dialog
        :title="titleDialog"
        :visible="showDialog"
        @open="create"
        @close="close"
        top="7vh"
        :close-on-click-modal="false"
    >
        <form autocomplete="off">
            <div class="form-body">
                <div class="row">
                    <div class="col-md-7 col-lg-7 col-xl-7 col-sm-7">
                        <div
                            class="form-group"
                            id="custom-select"
                            :class="{ 'has-danger': errors.item_id }"
                        >
                            <label class="control-label">
                                Producto/Servicio
                                <a
                                    v-if="typeUser != 'seller'"
                                    href="#"
                                    @click.prevent="showDialogNewItem = true"
                                    >[+ Nuevo]</a
                                >
                            </label>

                            <template
                                v-if="!search_item_by_barcode"
                                id="select-append"
                            >
                                <div
                                    class="el-input el-input-group el-input-group--append"
                                >
                                    <el-select
                                        :disabled="recordItem != null"
                                        v-model="form.item_id"
                                        @focus="$event.target.select()"
                                        ref="producto"
                                        @change="changeItem"
                                        filterable
                                        remote
                                        placeholder="Buscar"
                                        popper-class="el-select-items"
                                        @visible-change="focusTotalItem"
                                        slot="prepend"
                                        id="select-width"
                                        :remote-method="searchRemoteItems"
                                        :loading="loading_search"
                                        autofocus
                                    >
                                        <el-tooltip
                                            v-for="option in items"
                                            :key="option.id"
                                            placement="top"
                                        >
                                            <div slot="content">
                                                Marca: {{ option.brand }} <br />
                                                Categoria:
                                                {{ option.category }} <br />
                                                Stock: {{ option.stock }} <br />
                                                Precio:
                                                {{
                                                    option.currency_type_symbol
                                                }}
                                                {{ option.sale_unit_price }}
                                                <br />
                                            </div>

                                            <el-option
                                                :value="option.id"
                                                :label="option.full_description"
                                            ></el-option>
                                        </el-tooltip>
                                    </el-select>
                                    <el-tooltip
                                        slot="append"
                                        class="item"
                                        effect="dark"
                                        content="Ver Stock del Producto"
                                        placement="bottom"
                                        :disabled="recordItem != null"
                                    >
                                        <div class="el-input-group__append">
                                            <el-button
                                                :disabled="isEditItemNote"
                                                @click.prevent="
                                                    clickWarehouseDetail()
                                                "
                                                ><i class="fa fa-search"></i
                                            ></el-button>
                                        </div>
                                    </el-tooltip>
                                </div>
