                                            </td>
                                            <td class="text-center">
                                                {{ row.price1 }}
                                            </td>
                                            <td class="text-center">
                                                {{ row.price2 }}
                                            </td>
                                            <td class="text-center">
                                                {{ row.price3 }}
                                            </td>
                                            <td class="text-center">
                                                Precio {{ row.price_default }}
                                            </td>
                                            <td
                                                class="series-table-actions text-end"
                                            >
                                                <button
                                                    type="button"
                                                    class="btn waves-effect waves-light btn-sm btn-success"
                                                    @click.prevent="
                                                        selectedPrice(row)
                                                    "
                                                >
                                                    <i
                                                        class="el-icon-check"
                                                    ></i>
                                                </button>
                                            </td>
                                        </tr>
                                    </tbody>
                                </table>
                            </div>
